######################################################################
# Base64 primitives — generic openssl wrappers.
#
# Stateless — no sentinel; safe to call from any module regardless of
# kindle order. rbgo itself base64url-encodes JWT material; rbgg/rbgp
# decode SA private keys and rbfd decodes Cloud Build step outputs.
# The -A flag (suppress line wrapping) is load-bearing on every site
# and lives only here — a missing -A once lay dormant ~26 days before
# surfacing on a live API path (AUAAr cycle 4).

rbgo_base64_decode_string_to_file() {
  local -r z_b64="$1"
  local -r z_output="$2"
  test -n "${z_b64}"    || return 1
  test -n "${z_output}" || return 1
  printf '%s' "${z_b64}" | openssl enc -base64 -d -A > "${z_output}" || return 1
}

rbgo_base64_decode_file_to_file() {
  local -r z_input="$1"
  local -r z_output="$2"
  test -n "${z_input}"  || return 1
  test -n "${z_output}" || return 1
  test -f "${z_input}"  || return 1
  openssl enc -base64 -d -A < "${z_input}" > "${z_output}" || return 1
}

rbgo_base64_encode_string_capture() {
  local -r z_input="$1"
  printf '%s' "${z_input}" | openssl enc -base64 -A
}

rbgo_base64_encode_file_capture() {
  local -r z_file="$1"
  test -f "${z_file}" || return 1
  openssl enc -base64 -A < "${z_file}"
}

# Base64url transform: + -> -, / -> _, strip = padding. Stateless.
zrbgo_base64url_transform_capture() {
  local z_b64="$1"
  z_b64="${z_b64//+/-}"
  z_b64="${z_b64//\//_}"
  z_b64="${z_b64//=/}"
  printf '%s' "${z_b64}"
}

zrbgo_base64url_encode_capture() {
  zrbgo_sentinel

  local -r z_input="$1"

  local z_encoded
  z_encoded=$(rbgo_base64_encode_string_capture "${z_input}") || {
    buc_warn "openssl base64url encode failed"
    return 1
  }
  zrbgo_base64url_transform_capture "${z_encoded}"
}

zrbgo_base64url_encode_file_capture() {
  zrbgo_sentinel

  local -r z_file="$1"

  local z_encoded
  z_encoded=$(rbgo_base64_encode_file_capture "${z_file}") || {
    buc_warn "openssl base64url encode failed"
    return 1
  }
  zrbgo_base64url_transform_capture "${z_encoded}"
}

